import test from "node:test";
import assert from "node:assert/strict";
import { RetryBudget } from "../src/budget.mjs";
import { parseRetryAfter } from "../src/retry_after.mjs";
import { scheduleRetry } from "../src/scheduler.mjs";

test("numeric Retry-After is expressed in seconds", () => {
  assert.equal(parseRetryAfter("12", 500_000), 12_000);
});

test("a budget grants only its remaining duration", () => {
  const budget = new RetryBudget(5_000);
  assert.equal(budget.claim(4_000), 4_000);
  assert.equal(budget.claim(3_000), 1_000);
  assert.equal(budget.usedMs, 5_000);
});

test("an explicit zero delay is still enqueued", () => {
  const nowMs = 1_800_000_000_000;
  const queued = [];
  const runAt = scheduleRetry({
    retryAfter: new Date(nowMs).toUTCString(),
    nowMs,
    budget: new RetryBudget(1_000),
    enqueue: (time) => queued.push(time),
  });

  assert.equal(runAt, nowMs);
  assert.deepEqual(queued, [nowMs]);
});
